#!/usr/bin/env bash
# ══════════════════════════════════════════════════════════════════════════════
# 23_retry_missing_assemblies.sh — Retry downloading assemblies that previously failed
# ══════════════════════════════════════════════════════════════════════════════
#
# Reads pertussis_data/bp_genomes_qc/assemblies/_metadata/missing.txt (generated by 22_check_genome_completeness.py)
# and retries downloading them. Essentially a wrapper around the download logic.
#
# Usage:
#   python modules/step1_ingest/bin/raw_reads/22_check_genome_completeness.py   # first, generate missing list
#   bash modules/step1_ingest/bin/raw_reads/23_retry_missing_assemblies.sh       # then retry
#   bash modules/step1_ingest/bin/raw_reads/23_retry_missing_assemblies.sh --jobs 4
# ══════════════════════════════════════════════════════════════════════════════
set -euo pipefail

ROOT="$(cd "$(dirname "${BASH_SOURCE[0]}")/../../../.." && pwd)"
ASSEMBLY_DIR="${ROOT}/pertussis_data/bp_genomes_qc/assemblies"
META_DIR="${ASSEMBLY_DIR}/_metadata"
MISSING="${META_DIR}/missing.txt"
LOG_TSV="${META_DIR}/retry_log.tsv"
LOG_LOCK="${META_DIR}/retry_log.lock"
JOBS=4   # conservative default for retries

while [[ $# -gt 0 ]]; do
    case "$1" in
        --jobs|-j) JOBS="$2"; shift 2 ;;
        *) echo "Unknown: $1"; exit 1 ;;
    esac
done

if [[ ! -f "$MISSING" ]]; then
    echo "No missing list found. Run 22_check_genome_completeness.py first."
    exit 0
fi

TOTAL=$(wc -l < "$MISSING")
if [[ "$TOTAL" -eq 0 ]]; then
    echo "No missing assemblies. Database is complete."
    exit 0
fi

eval "$(conda shell.bash hook 2>/dev/null)" || true
conda activate ncbi_ds 2>/dev/null || true

if ! command -v datasets &>/dev/null; then
    echo "ERROR: 'datasets' CLI not found."
    exit 1
fi

echo "[$(date -Iseconds)] Retrying ${TOTAL} failed accessions (${JOBS} parallel jobs)"
echo -e "accession\tstatus\tsize_bytes\tduration_sec\ttimestamp" > "$LOG_TSV"

download_one() {
    local acc="$1"
    local out_dir="$2"
    local log_tsv="$3"
    local log_lock="$4"
    local dst="${out_dir}/${acc}.fasta"
    local t0=$(date +%s)

    if [[ -f "$dst" ]] && [[ -s "$dst" ]]; then
        ( flock -x 200; echo -e "${acc}\tskipped\t0\t0\t$(date -Iseconds)" >> "$log_tsv" ) 200>"$log_lock"
        return 0
    fi

    local tmpzip="/tmp/ncbi_${acc}_$$.zip"
    local tmpdir="/tmp/ncbi_${acc}_$$"

    # Retry with a short delay to avoid rate limiting
    sleep $(( RANDOM % 3 ))

    if datasets download genome accession "$acc" --include genome --filename "$tmpzip" 2>/dev/null; then
        mkdir -p "$tmpdir"
        if unzip -q -o "$tmpzip" -d "$tmpdir" 2>/dev/null; then
            local fna=$(find "${tmpdir}/ncbi_dataset/data/${acc}" -name '*.fna' -size +0 2>/dev/null | head -1)
            if [[ -n "$fna" ]]; then
                cp "$fna" "$dst"
                local sz=$(stat --format='%s' "$dst" 2>/dev/null || echo 0)
                local dur=$(( $(date +%s) - t0 ))
                ( flock -x 200; echo -e "${acc}\tok\t${sz}\t${dur}\t$(date -Iseconds)" >> "$log_tsv" ) 200>"$log_lock"
                echo "[ok] ${acc} (${dur}s)"
            else
                local dur=$(( $(date +%s) - t0 ))
                ( flock -x 200; echo -e "${acc}\tno_fna\t0\t${dur}\t$(date -Iseconds)" >> "$log_tsv" ) 200>"$log_lock"
                echo "[no_fna] ${acc}"
            fi
        else
            local dur=$(( $(date +%s) - t0 ))
            ( flock -x 200; echo -e "${acc}\tunzip_fail\t0\t${dur}\t$(date -Iseconds)" >> "$log_tsv" ) 200>"$log_lock"
            echo "[unzip_fail] ${acc}"
        fi
        rm -f "$tmpzip"; rm -rf "$tmpdir"
    else
        local dur=$(( $(date +%s) - t0 ))
        ( flock -x 200; echo -e "${acc}\tdl_fail\t0\t${dur}\t$(date -Iseconds)" >> "$log_tsv" ) 200>"$log_lock"
        echo "[dl_fail] ${acc}"
    fi
}

export -f download_one
export ASSEMBLY_DIR LOG_TSV LOG_LOCK

xargs -a "$MISSING" -I{} -P "$JOBS" \
    bash -c 'download_one "$1" "$ASSEMBLY_DIR" "$LOG_TSV" "$LOG_LOCK"' _ '{}'

echo ""
echo "[$(date -Iseconds)] Retry complete"
awk -F'\t' 'NR>1{c[$2]++}END{for(s in c)printf "  %s: %d\n",s,c[s]}' "$LOG_TSV"

echo ""
echo "Run 22_check_genome_completeness.py again to verify."
